import java.util.*;
import javax.naming.*;
import javax.naming.directory.*;

public class LdapUserSearch {
    public static void main(String[] args) throws NamingException {
        System.out.println(searchLdapByUsername("username"));
    }

    public static Map<String, String> searchLdapByUsername(String username) throws NamingException {
        // Prepare LDAP connection details
        String ldapURL = "ldaps://ldap.forumsys.com:636";
        String base = "dc=example,dc=com";
        
        Hashtable<String, String> environment = new Hashtable<>();
        environment.put(Context.INITIAL_CONTEXT_FACTORY, "com.sun.jndi.ldap.LdapCtxFactory");
        environment.put(Context.PROVIDER_URL, ldapURL);
        environment.put(Context.SECURITY_AUTHENTICATION, "simple");
        environment.put(Context.SECURITY_PRINCIPAL, username + "@example.com"); // Replace this with your own LDAP credentials if necessary
        environment.put(Context.SECURITY_CREDENTIALS, "password"); // Replace this with your own LDAP credentials if necessary
        
        // Create new initial context
        DirContext ctx = new InitialDirContext(environment);

        // Perform the search query
        SearchControls controls = new SearchControls();
        controls.setSearchScope(SearchControls.SUBTREE_SCOPE);
        NamingEnumeration<SearchResult> results = ctx.search("", "(uid=" + username + ")", controls);
        
        Map<String, String> userInfoMap = new HashMap<>();
        while (results.hasMoreElements()) {
            SearchResult sr = results.nextElement();
            
            Attributes attrs = sr.getAttributes();
            // Assuming email, full name and department are attributes in LDAP server's schema
            userInfoMap.put("email", attrs.get("mail").get().toString()); 
            userInfoMap.put("fullName", attrs.get("cn").get().toString());
            userInfoMap.put("department", attrs.get("ou").get().toString());
        }
        
        // Close the context and return populated map
        ctx.close();
        return userInfoMap;
    }
}